commit 278d7ee011e56770cca9b3ab3084557c5012d6b2
Author: David Carlier <devnexen@gmail.com>

mm/userfaultfd: detect VMA replacement after copy retry in mfill_copy_folio_retry()

This commit detects VMA replacements during the lock-dropped window in
mfill_copy_folio_retry() by taking a snapshot of the VMA's inode and flags.
It bails out with -EAGAIN if the VMA properties change after re-acquiring
the locks.

> diff --git a/mm/userfaultfd.c b/mm/userfaultfd.c
> index 481ec7eb4442..d10eb81dc3b2 100644
> --- a/mm/userfaultfd.c
> +++ b/mm/userfaultfd.c
> @@ -443,33 +443,83 @@ static int mfill_copy_folio_locked(struct folio *folio, unsigned long src_addr)
>  	return ret;
>  }
>  
> +struct vma_snapshot {
> +	struct inode *inode;
> +	vma_flags_t flags;
> +};
> +
> +static void vma_snapshot_take(struct vm_area_struct *vma,
> +			      struct vma_snapshot *s)
> +{
> +	memcpy(&s->flags, &vma->flags, sizeof(s->flags));

This isn't a bug, but struct vm_area_struct uses vm_flags, not flags. Will
this cause a compilation error?

> +	if (vma->vm_file) {
> +		s->inode = vma->vm_file->f_inode;
> +		ihold(s->inode);
> +	} else {
> +		s->inode = NULL;
> +	}
> +}
> +
> +static bool vma_snapshot_changed(struct vm_area_struct *vma,
> +				 struct vma_snapshot *s)
> +{
> +	if (memcmp(&s->flags, &vma->flags, sizeof(s->flags)))
> +		return true;
> +
> +	if (s->inode && vma->vm_file->f_inode != s->inode)

If the original VMA was file-backed (s->inode is non-NULL), but is
concurrently replaced by an anonymous VMA during the lock-dropped window,
vma->vm_file will be NULL. Does accessing vma->vm_file->f_inode here cause a
NULL pointer dereference?

> +		return true;
> +
> +	if (!s->inode && !vma_is_anonymous(vma))
> +		return true;
> +
> +	return false;
> +}
> +
> +static void vma_snapshot_release(struct vma_snapshot *s)
> +{
> +	if (s->inode) {
> +		iput(s->inode);

mfill_get_vma() acquires the mmap_read_lock() or per-VMA lock. If this iput()
drops the final reference to the inode, evict_inode() will run while holding
the mm locks.

Filesystem eviction paths often acquire locks (like i_rwsem) that invert
with the mmap lock. Can this cause an AB-BA deadlock? Should this take a
reference to the struct file via get_file() and release it with fput()
instead, which defers destruction safely?

> +		s->inode = NULL;
> +	}
> +}
> +
>  static int mfill_copy_folio_retry(struct mfill_state *state, struct folio *folio)
>  {
>  	unsigned long src_addr = state->src_addr;
> +	struct vma_snapshot s;

[ ... ]

>  	/* reget VMA and PMD, they could change underneath us */
>  	err = mfill_get_vma(state);
>  	if (err)
> -		return err;
> +		goto out;
>  
> -	err = mfill_establish_pmd(state);
> -	if (err)
> -		return err;
> +	if (vma_snapshot_changed(state->vma, &s)) {
> +		err = -EAGAIN;
> +		goto out;
> +	}
>  
> -	return 0;
> +	err = mfill_establish_pmd(state);
> +out:
> +	vma_snapshot_release(&s);
> +	return err;
>  }

